import React from 'react';
import './NavBar.css';

function NavBar({ active = 'record' }) {
  const tabs = ['calendar', 'record', 'community', 'profile'];
  return (
    <nav className="navbar">
      {tabs.map((tab) => (
        <button key={tab} className={`navbar-tab ${active === tab ? 'active' : ''}`}>
          {tab.toUpperCase()}
        </button>
      ))}
    </nav>
  );
}

export default NavBar;
